formulas.expression:
IF(
    /* TRAVA 1: Se começar com +, tem que ser +55 */
    AND(
        LEFT(BLANKVALUE({!Input_AccountSelection.selectedChoiceValues}, BLANKVALUE({!var_SelectedAccountPhone}, {!var_SelectedTelefoneComercial})), 1) = "+",
        LEFT(BLANKVALUE({!Input_AccountSelection.selectedChoiceValues}, BLANKVALUE({!var_SelectedAccountPhone}, {!var_SelectedTelefoneComercial})), 3) <> "+55"
    ),
    "NAO_FORMATAVEL",
    IF(
        /* TRAVA 2: Validação Rígida de Estrutura */
        OR(
            /* 10 Dígitos (ex: 11 8888-8888): Permite 6,7,8,9 (legado/incompleto) */
            AND(LEN({!form_CleanedPhoneNumber}) = 10, CONTAINS("6789", MID({!form_CleanedPhoneNumber}, 3, 1))),

            /* 11 Dígitos (ex: 11 98888-8888): OBRIGA ser 9 na 3ª casa (bloqueia Espanha sem +) */
            AND(LEN({!form_CleanedPhoneNumber}) = 11, MID({!form_CleanedPhoneNumber}, 3, 1) = "9"),

            /* 12 Dígitos (ex: 55 11 8888-8888): Permite 6,7,8,9 */
            AND(LEN({!form_CleanedPhoneNumber}) = 12, CONTAINS("6789", MID({!form_CleanedPhoneNumber}, 5, 1))),

            /* 13 Dígitos (ex: 55 11 98888-8888): OBRIGA ser 9 na 5ª casa */
            AND(LEN({!form_CleanedPhoneNumber}) = 13, MID({!form_CleanedPhoneNumber}, 5, 1) = "9")
        ),
        CASE(LEN({!form_CleanedPhoneNumber}),
            10, "55" & LEFT({!form_CleanedPhoneNumber}, 2) & "9" & RIGHT({!form_CleanedPhoneNumber}, 8),
            11, "55" & {!form_CleanedPhoneNumber},
            12, "55" & MID({!form_CleanedPhoneNumber}, 3, 2) & "9" & RIGHT({!form_CleanedPhoneNumber}, 8),
            13, {!form_CleanedPhoneNumber},
            "NAO_FORMATAVEL"
        ),
        "NAO_FORMATAVEL"
    )
)
